public int minValidSubarrays(int[] nums) {
    int count = 0;
    while(nums.length > 0) {
        int i;
        for (i = 0; i < nums.length; i++) {
            if (gcd(nums[i], nums[nums.length - 1]) > 1) {
                break;
            }
        }
        if (i == nums.length) {
            nums = Arrays.copyOf(nums, nums.length - 1);
            count++;
        } else {
            break;
        }
    }
    return (count > 0) ? count : -1;
}

private int gcd(int a, int b) {
    while (b != 0) {
        int temp = a % b;
        a = b;
        b = temp;
    }
    return a;
}
